/*! coi-serviceworker v0.1.7 (patched: localhost bypass)
 *  Original by Guido Zuidhof and contributors, MIT.
 *  Local change: skip COEP rewrapping for fetches to localhost / 127.0.0.1
 *  so cross-origin requests to a local dev server (e.g. gamma-compile-server
 *  on 127.0.0.1:8765) aren't intercepted and re-fetched in a way that
 *  breaks Chrome's Private Network Access policy. */
let coepCredentialless = false;

if (typeof window === "undefined") {
  // Service worker context.
  self.addEventListener("install", () => self.skipWaiting());

  self.addEventListener("activate", e => e.waitUntil(self.clients.claim()));

  self.addEventListener("message", e => {
    if (!e.data) return;
    if (e.data.type === "deregister") {
      self.registration.unregister()
        .then(() => self.clients.matchAll())
        .then(clients => clients.forEach(c => c.navigate(c.url)));
    } else if (e.data.type === "coepCredentialless") {
      coepCredentialless = e.data.value;
    }
  });

  self.addEventListener("fetch", function (e) {
    const r = e.request;
    if (r.cache === "only-if-cached" && r.mode !== "same-origin") return;

    // Local-network bypass. Requests to localhost / 127.0.0.1 are
    // intentionally not rewrapped — the SW's re-fetch strategy
    // collides with Chrome's Private Network Access policy and the
    // request fails before reaching the local server.
    let url;
    try { url = new URL(r.url); } catch (_) { return; }
    const host = url.hostname;
    if (host === "localhost" || host === "127.0.0.1" || host === "0.0.0.0" ||
        host === "[::1]" || host.endsWith(".localhost")) {
      // Don't intercept; browser handles it normally.
      return;
    }

    const s = coepCredentialless && r.mode === "no-cors"
      ? new Request(r, { credentials: "omit" })
      : r;

    e.respondWith(
      fetch(s)
        .then(resp => {
          if (resp.status === 0) return resp;
          const headers = new Headers(resp.headers);
          headers.set("Cross-Origin-Embedder-Policy",
            coepCredentialless ? "credentialless" : "require-corp");
          if (!coepCredentialless) headers.set("Cross-Origin-Resource-Policy", "cross-origin");
          headers.set("Cross-Origin-Opener-Policy", "same-origin");
          return new Response(resp.body, {
            status: resp.status,
            statusText: resp.statusText,
            headers
          });
        })
        .catch(err => console.error(err))
    );
  });
} else {
  // Page context — register the worker and prompt a reload on first install.
  (() => {
    const opts = {
      shouldRegister: () => true,
      shouldDeregister: () => false,
      coepCredentialless: () => !(window.chrome || window.netscape),
      doReload: () => window.location.reload(),
      quiet: false,
      ...window.coi
    };
    const nav = navigator;
    if (nav.serviceWorker && nav.serviceWorker.controller) {
      nav.serviceWorker.controller.postMessage({
        type: "coepCredentialless",
        value: opts.coepCredentialless()
      });
      if (opts.shouldDeregister()) {
        nav.serviceWorker.controller.postMessage({ type: "deregister" });
      }
    }
    if (window.crossOriginIsolated === false && opts.shouldRegister()) {
      if (window.isSecureContext) {
        if (nav.serviceWorker) {
          nav.serviceWorker.register(window.document.currentScript.src).then(
            reg => {
              if (!opts.quiet) console.log("COOP/COEP Service Worker registered", reg.scope);
              reg.addEventListener("updatefound", () => {
                if (!opts.quiet) console.log("Reloading page to make use of updated COOP/COEP Service Worker.");
                opts.doReload();
              });
              if (reg.active && !nav.serviceWorker.controller) {
                if (!opts.quiet) console.log("Reloading page to make use of COOP/COEP Service Worker.");
                opts.doReload();
              }
            },
            err => {
              if (!opts.quiet) console.error("COOP/COEP Service Worker failed to register:", err);
            }
          );
        }
      } else if (!opts.quiet) {
        console.log("COOP/COEP Service Worker not registered, a secure context is required.");
      }
    }
  })();
}
